from itertools import combinations

def connected(n, edges):
    # edges set frozenset pairs
    if n==0: return True
    adj=[set() for _ in range(n)]
    for i,j in edges:
        adj[i].add(j); adj[j].add(i)
    seen={0}; stack=[0]
    while stack:
        v=stack.pop()
        for w in adj[v]-seen:
            seen.add(w); stack.append(w)
    return len(seen)==n

def check(n):
    verts=range(n)
    allpairs=set(tuple(sorted(p)) for p in combinations(verts,2))
    bad=[]
    for mask in range(1<<len(allpairs)):
        pairs=list(allpairs)
        E=set(pairs[i] for i in range(len(pairs)) if mask>>i & 1)
        comp=allpairs-E
        if not connected(n, comp): continue
        for v in verts:
            C=[r for r in verts if r!=v and tuple(sorted((v,r))) not in E]
            if not C:
                bad.append((E,v,"empty C")); break
            if len(C)==1 and n>=3:
                r=C[0]
                ok=False
                for s in verts:
                    if s not in (v,r) and tuple(sorted((v,s))) in E and tuple(sorted((r,s))) not in E:
                        ok=True
                if not ok:
                    bad.append((E,v,"no s")); break
    return bad
for n in range(3,7):
    b=check(n)
    print(n,len(b))
